class FileResDto {
  @Expose() id: string;
  @Expose() filename: string;
  @Expose() originalName: string;
  @Expose() mimeType: string;
  @Expose() size: number;
  @Expose() @Transform(({ obj }) => `${(obj.size / 1024).toFixed(2)} KB`) sizeFormatted: string;
  @Expose() createdAt: Date;
  // Excludes: s3Key, s3Bucket, domainID, userID, deletedAt
}

